global.schema:
type PhClintProjectState {
  name: String
  scope: String
  version: String!
  description: String!
  features: PhClintFeatures!
  packages: [PowerhousePackage!]!
  externalSkills: [ExternalSkill!]!
  publishHistory: [PublishRecord!]!
  deployment: PhClintDeployment!
}

type PhClintFeatures {
  powerhouse: PowerhouseLevel!
  mastra: PhClintMastraFeature!
  routine: PhClintRoutineFeature!
}

enum PowerhouseLevel {
  Disabled
  Reactor
  Switchboard
  Connect
}

type PhClintMastraFeature {
  enabled: Boolean!
  mainAgent: PhClintMainAgent
  subAgents: [PhClintSubAgent!]!
  models: [PhClintAgentModel!]!
  profiles: [PhClintAgentProfile!]!
  common: PhClintMastraCommon!
}

type PhClintMainAgent {
  id: OID!
  name: String!
  description: String
  image: String
  modelId: OID!
  profileIds: [OID!]!
  skills: [String!]!
  toolPatterns: [String!]!
}

type PhClintSubAgent {
  id: OID!
  name: String!
  description: String!
  modelId: OID!
  profileIds: [OID!]!
  skills: [String!]!
  toolPatterns: [String!]!
}

type PhClintMastraCommon {
  enableChat: Boolean!
}

type PhClintAgentModel {
  id: OID!
  isDefault: Boolean!
}

type PhClintAgentProfile {
  id: OID!
  title: String!
  content: String!
}

type PhClintRoutineFeature {
  enabled: Boolean!
}

type PowerhousePackage {
  id: OID!
  packageName: String!
  documentTypes: [String!]!
  version: String
  managed: Boolean!
}

type ExternalSkill {
  id: OID!
  name: String!
  githubUrl: URL!
}

enum PublishTag {
  Dev
  Staging
  Production
}

enum PublishStatus {
  Pending
  InProgress
  Succeeded
  Failed
}

type PublishRecord {
  id: OID!
  tag: PublishTag!
  version: String!
  timestamp: DateTime!
  status: PublishStatus!
}

type PhClintDeployment {
  proxyEnabled: Boolean!
  observabilityEnabled: Boolean!
  supportedResources: [String!]!
}

