operations.schema:
input SetDescriptionInput {
  description: String!
}

input SetVersionInput {
  version: String!
}

operations.reducer:
if (!/^\d+\.\d+\.\d+(?:-[0-9A-Za-z.-]+)?(?:\+[0-9A-Za-z.-]+)?$/.test(action.input.version)) {
  throw new InvalidVersionError(`Invalid version: ${action.input.version}`);
}
state.version = action.input.version;

operations.schema:
input SetPackageIdentifierInput {
  identifier: String!
}

operations.reducer:
const trimmed = action.input.identifier.trim();
if (!trimmed) {
  throw new InvalidPackageIdentifierError('Package identifier must not be empty');
}
let scopePart = null;
let namePart = trimmed;
if (trimmed.includes('/')) {
  const parts = trimmed.split('/');
  if (parts.length !== 2 || !parts[0] || !parts[1]) {
    throw new InvalidPackageIdentifierError(`Invalid package identifier: ${trimmed}`);
  }
  scopePart = parts[0].replace(/^@/, '');
  namePart = parts[1];
}
if (scopePart !== null) {
  if (!/^[a-z][a-z0-9-]*$/.test(scopePart)) {
    throw new InvalidPackageIdentifierError(`Invalid scope: ${scopePart}`);
  }
}
if (!namePart.endsWith('-cli')) {
  namePart = namePart + '-cli';
}
if (!/^[a-z][a-z0-9-]*$/.test(namePart)) {
  throw new InvalidPackageIdentifierError(`Invalid package name: ${namePart}`);
}
state.scope = scopePart ? `@${scopePart}` : null;
state.name = namePart;
const managed = state.packages.find((p) => p.managed);
if (managed) {
  const appBase = namePart.replace(/-cli$/, '-app');
  managed.packageName = scopePart ? `@${scopePart}/${appBase}` : appBase;
  managed.id = `app-${namePart}`;
}

operations.schema:
input SetPowerhouseLevelInput {
  level: PowerhouseLevel!
  skipAutoProxy: Boolean
}

operations.reducer:
const LEVELS = ['Disabled', 'Reactor', 'Switchboard', 'Connect'];
const current = LEVELS.indexOf(state.features.powerhouse);
const next = LEVELS.indexOf(action.input.level);
if (current >= 1 && next < 1) {
  throw new CannotLowerPowerhouseError(
    'Cannot lower Powerhouse level below Reactor once enabled',
  );
}
state.features.powerhouse = action.input.level;
if (current === 0 && next >= 1) {
  const hasManaged = state.packages.some((p) => p.managed);
  if (!hasManaged) {
    const baseName = state.name
      ? state.name.replace(/-cli$/, '-app')
      : 'app';
    const appName =
      state.scope && state.name
        ? `${state.scope}/${baseName}`
        : baseName;
    state.packages.push({
      id: `app-${state.name || 'managed'}`,
      packageName: appName,
      documentTypes: ['*/*'],
      version: null,
      managed: true,
    });
  }
}
if (next >= 2 && !action.input.skipAutoProxy) {
  state.deployment.proxyEnabled = true;
}

operations.schema:
input EnableRoutineInput {
  _: Boolean
}

input DisableRoutineInput {
  _: Boolean
}

input AddPowerhousePackageInput {
  id: OID!
  packageName: String!
}

operations.reducer:
const exists = state.packages.find(
  (p) =>
    p.id === action.input.id ||
    p.packageName === action.input.packageName,
);
if (exists) {
  throw new DuplicatePackageError(
    `Package already exists: ${action.input.packageName}`,
  );
}
state.packages.push({
  id: action.input.id,
  packageName: action.input.packageName,
  documentTypes: [],
  version: null,
  managed: false,
});

operations.schema:
input RemovePowerhousePackageInput {
  id: OID!
}

operations.reducer:
const idx = state.packages.findIndex((p) => p.id === action.input.id);
if (idx === -1) {
  throw new PackageNotFoundError(`Package not found: ${action.input.id}`);
}
const pkg = state.packages[idx];
if (pkg.managed) {
  throw new CannotRemoveManagedPackageError(
    "Cannot remove a managed package",
  );
}
state.packages.splice(idx, 1);

operations.schema:
input AddPackageDocumentTypeInput {
  packageId: OID!
  documentType: String!
}

operations.reducer:
if (action.input.documentType !== '*/*' && !/^[a-z0-9-]+\/[a-z0-9-]+$/.test(action.input.documentType)) {
  throw new InvalidDocumentTypeError(
    `Invalid document type format: ${action.input.documentType}. Expected org/name.`,
  );
}
const pkg = state.packages.find((p) => p.id === action.input.packageId);
if (!pkg) {
  throw new PackageNotFoundError(
    `Package not found: ${action.input.packageId}`,
  );
}
if (action.input.documentType === '*/*') {
  pkg.documentTypes.length = 0;
  pkg.documentTypes.push('*/*');
  return;
}
if (pkg.documentTypes.includes('*/*')) {
  return;
}
if (pkg.documentTypes.includes(action.input.documentType)) {
  throw new DuplicateDocumentTypeError(
    `Document type already registered: ${action.input.documentType}`,
  );
}
pkg.documentTypes.push(action.input.documentType);

operations.schema:
input RemovePackageDocumentTypeInput {
  packageId: OID!
  documentType: String!
}

operations.reducer:
const pkg = state.packages.find(p => p.id === action.input.packageId);
if (!pkg) {
  throw new PackageNotFoundError(`Package not found: ${action.input.packageId}`);
}
const idx = pkg.documentTypes.indexOf(action.input.documentType);
if (idx === -1) {
  throw new DocumentTypeNotFoundError(`Document type not found: ${action.input.documentType}`);
}
pkg.documentTypes.splice(idx, 1);

operations.schema:
input SetPackageVersionInput {
  packageId: OID!
  version: String
}

operations.reducer:
const pkg = state.packages.find((p) => p.id === action.input.packageId);
if (!pkg) {
  throw new PackageNotFoundError(
    `Package not found: ${action.input.packageId}`,
  );
}
if (action.input.version != null) {
  const SEMVER = /^\d+\.\d+\.\d+(?:-[0-9A-Za-z.-]+)?(?:\+[0-9A-Za-z.-]+)?$/;
  if (!SEMVER.test(action.input.version)) {
    throw new InvalidVersionError(
      `Invalid version: ${action.input.version}`,
    );
  }
}
pkg.version = action.input.version || null;

operations.schema:
input AddExternalSkillInput {
  id: OID!
  name: String!
  githubUrl: URL!
}

operations.reducer:
if (!/^[a-z][a-z0-9-]*$/.test(action.input.name)) {
  throw new InvalidSkillNameError(`Invalid skill name: ${action.input.name}. Must be lowercase kebab-case.`);
}
const exists = state.externalSkills.find(s => s.id === action.input.id || s.name === action.input.name);
if (exists) {
  throw new DuplicateSkillError(`Skill already exists: ${action.input.name}`);
}
state.externalSkills.push({
  id: action.input.id,
  name: action.input.name,
  githubUrl: action.input.githubUrl,
});

operations.schema:
input RemoveExternalSkillInput {
  id: OID!
}

operations.reducer:
const idx = state.externalSkills.findIndex(s => s.id === action.input.id);
if (idx === -1) {
  throw new SkillNotFoundError(`Skill not found: ${action.input.id}`);
}
state.externalSkills.splice(idx, 1);

operations.schema:
input SetExternalSkillNameInput {
  id: OID!
  name: String!
}

operations.reducer:
const skill = state.externalSkills.find(s => s.id === action.input.id);
if (!skill) {
  throw new SkillNotFoundError(`Skill not found: ${action.input.id}`);
}
if (!/^[a-z][a-z0-9-]*$/.test(action.input.name)) {
  throw new InvalidSkillNameError(`Invalid skill name: ${action.input.name}. Must be lowercase kebab-case.`);
}
const duplicate = state.externalSkills.find(s => s.name === action.input.name && s.id !== action.input.id);
if (duplicate) {
  throw new DuplicateSkillError(`Skill name already in use: ${action.input.name}`);
}
skill.name = action.input.name;

operations.schema:
input SetExternalSkillGithubUrlInput {
  id: OID!
  githubUrl: URL!
}

operations.reducer:
const skill = state.externalSkills.find(s => s.id === action.input.id);
if (!skill) {
  throw new SkillNotFoundError(`Skill not found: ${action.input.id}`);
}
skill.githubUrl = action.input.githubUrl;

operations.schema:
input BumpVersionInput {
  version: String!
}

operations.reducer:
if (!/^\d+\.\d+\.\d+(?:-[0-9A-Za-z.-]+)?(?:\+[0-9A-Za-z.-]+)?$/.test(action.input.version)) {
  throw new InvalidVersionError(`Invalid version: ${action.input.version}`);
}
state.version = action.input.version;

operations.schema:
input PublishDevInput {
  id: OID!
  timestamp: DateTime!
}

operations.reducer:
state.publishHistory.push({
  id: action.input.id,
  tag: 'Dev',
  version: state.version,
  timestamp: action.input.timestamp,
  status: 'Pending',
});

operations.schema:
input PublishStagingInput {
  id: OID!
  timestamp: DateTime!
}

operations.reducer:
state.publishHistory.push({
  id: action.input.id,
  tag: 'Staging',
  version: state.version,
  timestamp: action.input.timestamp,
  status: 'Pending',
});

operations.schema:
input PublishProductionInput {
  id: OID!
  timestamp: DateTime!
}

operations.reducer:
state.publishHistory.push({
  id: action.input.id,
  tag: 'Production',
  version: state.version,
  timestamp: action.input.timestamp,
  status: 'Pending',
});

operations.schema:
input SetPublishStatusInput {
  id: OID!
  status: PublishStatus!
}

operations.reducer:
const record = state.publishHistory.find(r => r.id === action.input.id);
if (!record) {
  throw new PublishRecordNotFoundError(`Publish record not found: ${action.input.id}`);
}
record.status = action.input.status;

state.name = action.input.name;
state.scope = action.input.scope || null;
state.version = action.input.version;
state.description = action.input.description;
state.features.powerhouse = action.input.powerhouse;
state.features.mastra.enabled = action.input.mastraEnabled;
state.features.routine.enabled = action.input.routineEnabled;

const appBase = action.input.name.replace(/-cli$/, '-app');
const appPkgName = action.input.scope
  ? `${action.input.scope}/${appBase}`
  : appBase;
const phEnabled = action.input.powerhouse !== 'Disabled';

state.packages = action.input.packages.map((p) => ({
  id: p.id,
  packageName: p.packageName,
  documentTypes: [...p.documentTypes],
  version: p.version || null,
  managed: phEnabled && p.packageName === appPkgName,
}));
state.externalSkills = action.input.externalSkills.map((s) => ({
  id: s.id,
  name: s.name,
  githubUrl: s.githubUrl,
}));

state.features.mastra.models = action.input.models.map((m) => ({
  id: m.id,
  isDefault: m.isDefault,
}));
state.features.mastra.profiles = action.input.profiles.map((p) => ({
  id: p.id,
  title: p.title,
  content: p.content,
}));

if (action.input.mainAgent && state.features.mastra.enabled) {
  const m = action.input.mainAgent;
  let image = null;
  if (m.image) {
    if (!/^data:[a-z]+\/[a-z0-9.+-]+;base64,/.test(m.image)) {
      throw new InvalidAgentImageError(
        'Invalid image: must be a data URL (data:<mime>;base64,...)',
      );
    }
    image = m.image;
  }
  state.features.mastra.mainAgent = {
    id: m.id,
    name: m.name,
    description: m.description || null,
    image,
    modelId: m.modelId,
    profileIds: [...m.profileIds],
    skills: [...m.skills],
    toolPatterns: [...m.toolPatterns],
  };
} else {
  state.features.mastra.mainAgent = null;
}

if (state.features.mastra.enabled) {
  state.features.mastra.subAgents = action.input.subAgents.map((s) => ({
    id: s.id,
    name: s.name,
    description: s.description,
    modelId: s.modelId,
    profileIds: [...s.profileIds],
    skills: [...s.skills],
    toolPatterns: [...s.toolPatterns],
  }));
} else {
  state.features.mastra.subAgents = [];
}

if (
  action.input.enableChat &&
  state.features.mastra.enabled &&
  state.features.powerhouse !== 'Disabled'
) {
  state.features.mastra.common.enableChat = true;
  const CLINT_COMMON_PKG = '@powerhousedao/clint-common';
  const CHAT_DOC_TYPE = 'powerhouse/chat-session';
  const existing = state.packages.find(
    (p) => p.packageName === CLINT_COMMON_PKG,
  );
  if (!existing) {
    state.packages.push({
      id: 'pkg-clint-common',
      packageName: CLINT_COMMON_PKG,
      documentTypes: [CHAT_DOC_TYPE],
      version: null,
      managed: true,
    });
  } else if (!existing.documentTypes.includes(CHAT_DOC_TYPE)) {
    existing.documentTypes.push(CHAT_DOC_TYPE);
  }
} else {
  state.features.mastra.common.enableChat = false;
}

state.deployment.proxyEnabled = action.input.proxyEnabled ?? false;
state.deployment.observabilityEnabled = action.input.observabilityEnabled ?? false;
state.deployment.supportedResources = action.input.supportedResources
  ? [...action.input.supportedResources]
  : [];

operations.schema:
input AddSupportedResourceInput {
  resource: String!
}

operations.reducer:
if (state.deployment.supportedResources.includes(action.input.resource)) {
  throw new DuplicateResourceError(`Resource already exists: ${action.input.resource}`);
}
state.deployment.supportedResources.push(action.input.resource);

operations.schema:
input RemoveSupportedResourceInput {
  resource: String!
}

operations.reducer:
const idx = state.deployment.supportedResources.indexOf(action.input.resource);
if (idx === -1) {
  throw new ResourceNotFoundError(`Resource not found: ${action.input.resource}`);
}
state.deployment.supportedResources.splice(idx, 1);

operations.schema:
input SetProxyEnabledInput {
  enabled: Boolean!
}

input SetObservabilityEnabledInput {
  enabled: Boolean!
}

input EnableMastraInput {
  agentId: OID!
  agentName: String!
}

operations.reducer:
if (!/^[a-z][a-z0-9-]*$/.test(action.input.agentId)) {
  throw new InvalidAgentIdError(
    `Invalid agent ID: ${action.input.agentId}. Must be lowercase kebab-case.`,
  );
}
const trimmedName = action.input.agentName.trim();
if (!trimmedName) {
  throw new InvalidAgentNameError('Agent name must not be empty.');
}
state.features.mastra.enabled = true;
if (state.features.mastra.models.length === 0) {
  state.features.mastra.models.push({ id: 'clint/demo-agent', isDefault: true });
}
if (state.features.mastra.profiles.length === 0) {
  state.features.mastra.profiles.push({ id: 'base', title: 'Base Profile', content: 'You are a helpful assistant.' });
}
const existing = state.features.mastra.mainAgent;
if (!existing) {
  state.features.mastra.mainAgent = {
    id: action.input.agentId,
    name: trimmedName,
    description: null,
    image: null,
    modelId: 'clint/demo-agent',
    profileIds: ['base'],
    skills: [],
    toolPatterns: [],
  };
} else {
  existing.id = action.input.agentId;
  existing.name = trimmedName;
}

operations.schema:
input DisableMastraInput {
  _: Boolean
}

operations.reducer:
state.features.mastra.enabled = false;
state.features.mastra.mainAgent = null;
state.features.mastra.subAgents = [];
state.features.mastra.models = [];
state.features.mastra.profiles = [];
state.features.mastra.common.enableChat = false;
const ccIdx = state.packages.findIndex(
  (p) => p.packageName === '@powerhousedao/clint-common' && p.managed,
);
if (ccIdx !== -1) {
  state.packages.splice(ccIdx, 1);
}

operations.schema:
input SetEnableChatInput {
  enabled: Boolean!
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot toggle chat when Mastra is disabled.');
}
if (state.features.powerhouse === 'Disabled') {
  throw new PowerhouseNotEnabledError('Cannot toggle chat when Powerhouse is disabled.');
}
state.features.mastra.common.enableChat = action.input.enabled;
const CLINT_COMMON_PKG = '@powerhousedao/clint-common';
const CHAT_DOC_TYPE = 'powerhouse/chat-session';
if (action.input.enabled) {
  const existing = state.packages.find((p) => p.packageName === CLINT_COMMON_PKG);
  if (!existing) {
    state.packages.push({
      id: 'pkg-clint-common',
      packageName: CLINT_COMMON_PKG,
      documentTypes: [CHAT_DOC_TYPE],
      version: null,
      managed: true,
    });
  } else if (!existing.documentTypes.includes(CHAT_DOC_TYPE)) {
    existing.documentTypes.push(CHAT_DOC_TYPE);
  }
} else {
  const idx = state.packages.findIndex(
    (p) => p.packageName === CLINT_COMMON_PKG && p.managed,
  );
  if (idx !== -1) {
    const pkg = state.packages[idx];
    if (pkg.documentTypes.length === 1 && pkg.documentTypes[0] === CHAT_DOC_TYPE) {
      state.packages.splice(idx, 1);
    } else {
      const dtIdx = pkg.documentTypes.indexOf(CHAT_DOC_TYPE);
      if (dtIdx !== -1) pkg.documentTypes.splice(dtIdx, 1);
    }
  }
}

operations.schema:
input AddModelInput {
  id: OID!
  isDefault: Boolean
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot add model when Mastra is disabled.');
}
if (!/^[a-z0-9-]+\/[a-z0-9._-]+$/.test(action.input.id)) {
  throw new InvalidModelIdError(`Invalid model ID: ${action.input.id}. Must be provider/model-name format.`);
}
if (state.features.mastra.models.find(m => m.id === action.input.id)) {
  throw new DuplicateModelError(`Model already exists: ${action.input.id}`);
}
const isFirst = state.features.mastra.models.length === 0;
const makeDefault = isFirst || action.input.isDefault === true;
if (makeDefault) {
  for (const m of state.features.mastra.models) {
    m.isDefault = false;
  }
}
state.features.mastra.models.push({
  id: action.input.id,
  isDefault: makeDefault,
});

operations.schema:
input RemoveModelInput {
  id: OID!
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot remove model when Mastra is disabled.');
}
const idx = state.features.mastra.models.findIndex((m) => m.id === action.input.id);
if (idx === -1) {
  throw new ModelNotFoundError(`Model not found: ${action.input.id}`);
}
const main = state.features.mastra.mainAgent;
const usedByMain = !!main && main.modelId === action.input.id;
const usedBySub = state.features.mastra.subAgents.some(
  (s) => s.modelId === action.input.id,
);
if (usedByMain || usedBySub) {
  throw new ModelInUseError(
    `Model ${action.input.id} is in use by an agent.`,
  );
}
const wasDefault = state.features.mastra.models[idx].isDefault;
state.features.mastra.models.splice(idx, 1);
if (wasDefault && state.features.mastra.models.length > 0) {
  state.features.mastra.models[0].isDefault = true;
}

operations.schema:
input SetDefaultModelInput {
  id: OID!
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot set default model when Mastra is disabled.');
}
const model = state.features.mastra.models.find(m => m.id === action.input.id);
if (!model) {
  throw new ModelNotFoundError(`Model not found: ${action.input.id}`);
}
for (const m of state.features.mastra.models) {
  m.isDefault = false;
}
model.isDefault = true;

operations.schema:
input AddProfileInput {
  id: OID!
  title: String!
  content: String!
  insertBefore: OID
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot add profile when Mastra is disabled.');
}
if (!/^[a-z][a-z0-9-]*$/.test(action.input.id)) {
  throw new InvalidProfileIdError(`Invalid profile ID: ${action.input.id}. Must be lowercase kebab-case.`);
}
if (state.features.mastra.profiles.find(p => p.id === action.input.id)) {
  throw new DuplicateProfileError(`Profile already exists: ${action.input.id}`);
}
const profile = {
  id: action.input.id,
  title: action.input.title,
  content: action.input.content,
};
if (action.input.insertBefore) {
  const beforeIdx = state.features.mastra.profiles.findIndex(p => p.id === action.input.insertBefore);
  if (beforeIdx === -1) {
    throw new ProfileNotFoundError(`insertBefore profile not found: ${action.input.insertBefore}`);
  }
  state.features.mastra.profiles.splice(beforeIdx, 0, profile);
} else {
  state.features.mastra.profiles.push(profile);
}

operations.schema:
input UpdateProfileInput {
  id: OID!
  title: String
  content: String
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot update profile when Mastra is disabled.');
}
const profile = state.features.mastra.profiles.find(p => p.id === action.input.id);
if (!profile) {
  throw new ProfileNotFoundError(`Profile not found: ${action.input.id}`);
}
if (action.input.title) profile.title = action.input.title;
if (action.input.content) profile.content = action.input.content;

operations.schema:
input RemoveProfileInput {
  id: OID!
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot remove profile when Mastra is disabled.');
}
const idx = state.features.mastra.profiles.findIndex((p) => p.id === action.input.id);
if (idx === -1) {
  throw new ProfileNotFoundError(`Profile not found: ${action.input.id}`);
}
const main = state.features.mastra.mainAgent;
const usedByMain = !!main && main.profileIds.includes(action.input.id);
const usedBySub = state.features.mastra.subAgents.some(
  (s) => s.profileIds.includes(action.input.id),
);
if (usedByMain || usedBySub) {
  throw new ProfileInUseError(
    `Profile ${action.input.id} is in use by an agent.`,
  );
}
state.features.mastra.profiles.splice(idx, 1);

operations.schema:
input ReorderProfilesInput {
  ids: [OID!]!
  insertBefore: OID
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot reorder profiles when Mastra is disabled.');
}
const moving = [];
for (const id of action.input.ids) {
  const profile = state.features.mastra.profiles.find(p => p.id === id);
  if (!profile) {
    throw new ProfileNotFoundError(`Profile not found: ${id}`);
  }
  moving.push(profile);
}
state.features.mastra.profiles = state.features.mastra.profiles.filter(p => !action.input.ids.includes(p.id));
if (action.input.insertBefore) {
  const beforeIdx = state.features.mastra.profiles.findIndex(p => p.id === action.input.insertBefore);
  if (beforeIdx === -1) {
    throw new ProfileNotFoundError(`insertBefore profile not found: ${action.input.insertBefore}`);
  }
  state.features.mastra.profiles.splice(beforeIdx, 0, ...moving);
} else {
  state.features.mastra.profiles.push(...moving);
}

operations.schema:
input SetMainAgentNameInput {
