operations.schema:
input AddAgentProfileRefInput {
  agentId: OID!
  profileId: OID!
  insertBefore: OID
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot add profile ref when Mastra is disabled.');
}
const main = state.features.mastra.mainAgent;
let agent;
if (main && main.id === action.input.agentId) {
  agent = main;
} else {
  agent = state.features.mastra.subAgents.find(
    (s) => s.id === action.input.agentId,
  );
}
if (!agent) {
  throw new AgentNotFoundError(`Agent not found: ${action.input.agentId}`);
}
if (!state.features.mastra.profiles.find((p) => p.id === action.input.profileId)) {
  throw new ProfileReferenceNotFoundError(
    `Profile not in library: ${action.input.profileId}`,
  );
}
if (agent.profileIds.includes(action.input.profileId)) {
  return;
}
if (action.input.insertBefore) {
  const beforeIdx = agent.profileIds.indexOf(action.input.insertBefore);
  if (beforeIdx === -1) {
    throw new ProfileReferenceNotFoundError(
      `insertBefore profile not in agent's profileIds: ${action.input.insertBefore}`,
    );
  }
  agent.profileIds.splice(beforeIdx, 0, action.input.profileId);
} else {
  agent.profileIds.push(action.input.profileId);
}

