input RemoveAgentProfileRefInput {
  agentId: OID!
  profileId: OID!
}

operations.reducer:
if (!state.features.mastra.enabled) {
  throw new MastraNotEnabledError('Cannot remove profile ref when Mastra is disabled.');
}
const main = state.features.mastra.mainAgent;
let agent;
if (main && main.id === action.input.agentId) {
